	private void OpenSponsorWindow()
	{
		if (_sponsorWindow == null || ((Control)_sponsorWindow).Disposed)
		{
			_sponsorWindow = new CivSponsorWindow();
			MainMenuSystem mainMenuSystem = _entityManager.System<MainMenuSystem>();
			mainMenuSystem.OnSkinStateReceived += _sponsorWindow.UpdateFromSkinState;
			((BaseWindow)_sponsorWindow).OnClose += delegate
			{
				mainMenuSystem.OnSkinStateReceived -= _sponsorWindow.UpdateFromSkinState;
			};
		}
		((BaseWindow)_sponsorWindow).OpenCentered();
		if (((Control)this).UserInterfaceManager.GetUIController<MainMenuUIController>().TryGetCachedSponsorData(out SponsorTierInfo displayTier, out List<SponsorActiveTierInfo> activeTiers, out SponsorDisplayMode displayMode, out string preferredTierKey, out Dictionary<string, int> permissions, out List<SponsorPermissionDetailInfo> permissionDetails))
		{
			_sponsorWindow.UpdateSponsorData(permissions, permissionDetails, displayTier, activeTiers, displayMode, preferredTierKey);
		}
		_entityManager.System<MainMenuSystem>().RequestSkinState();
	}

	private void OpenLoadoutWindow()
	{
		if (_loadoutWindow == null || ((Control)_loadoutWindow).Disposed)
		{
			CivLoadoutWindow window = new CivLoadoutWindow();
			window.OnApplyOutfit += delegate(Dictionary<string, string> outfit)
			{
				_entityManager.RaisePredictiveEvent<SkinApplyMessage>(new SkinApplyMessage(outfit));
			};
			MainMenuSystem mainMenuSystem = _entityManager.System<MainMenuSystem>();
			mainMenuSystem.OnSkinStateReceived += window.UpdateFromSkinState;
			((BaseWindow)window).OnClose += delegate
			{
				mainMenuSystem.OnSkinStateReceived -= window.UpdateFromSkinState;
			};
			_loadoutWindow = window;
		}
		((BaseWindow)_loadoutWindow).OpenCentered();
		_entityManager.System<MainMenuSystem>().RequestSkinState(force: true);
		_entityManager.System<CivLoadoutSystem>().RequestState();
	}

