		//IL_025e: Unknown result type (might be due to invalid IL or missing references)
		//IL_0216: Unknown result type (might be due to invalid IL or missing references)
		if (!state.Enabled)
		{
			AssignmentTeam.Text = Loc.GetString("civ-lobby-gui-tdm-not-selected");
			AssignmentTeam.FontColorOverride = AssignmentTeamMuted;
			AssignmentRole.Text = Loc.GetString("civ-lobby-gui-pick-mode");
			AssignmentCommander.Text = string.Empty;
			return;
		}
		CivRosterPlayerEntry civRosterPlayerEntry = state.Players.FirstOrDefault((CivRosterPlayerEntry p) => p.IsSelected);
		int? num = civRosterPlayerEntry?.TeamId;
		object obj;
		if (num.HasValue)
		{
			int tid = num.GetValueOrDefault();
			obj = state.Teams.FirstOrDefault((CivRosterTeamEntry t) => t.TeamId == tid);
		}
		else
		{
			obj = null;
		}
		CivRosterTeamEntry civRosterTeamEntry = (CivRosterTeamEntry)obj;
		if (civRosterPlayerEntry == null || civRosterTeamEntry == null)
		{
			AssignmentTeam.Text = Loc.GetString("civ-lobby-gui-assignment-unassigned");
			AssignmentTeam.FontColorOverride = AssignmentTeamMuted;
			AssignmentRole.Text = Loc.GetString("civ-lobby-gui-assignment-pick");
			AssignmentCommander.Text = string.Empty;
			return;
		}
		AssignmentTeam.Text = civRosterTeamEntry.TeamName.ToUpperInvariant();
		AssignmentTeam.FontColorOverride = ((civRosterTeamEntry.TeamId == 1) ? AssignmentTeam1 : AssignmentTeam2);
		string displayName = CivTdmClassHelper.GetDisplayName(civRosterPlayerEntry.Class);
		AssignmentRole.Text = (civRosterPlayerEntry.SquadId.HasValue ? Loc.GetString("civ-lobby-gui-assignment-squad", new(string, object)[2]
		{
			("class", displayName),
			("squad", civRosterPlayerEntry.SquadId)
		}) : Loc.GetString("civ-lobby-gui-assignment-no-squad", new(string, object)[1] { ("class", displayName) }));
		if (string.IsNullOrWhiteSpace(civRosterTeamEntry.CommanderName))
		{
			AssignmentCommander.Text = Loc.GetString("civ-lobby-gui-commander-none");
			AssignmentCommander.FontColorOverride = AssignmentCommanderMissing;
		}
		else
		{
			AssignmentCommander.Text = Loc.GetString("civ-lobby-gui-commander", new(string, object)[1] { ("name", civRosterTeamEntry.CommanderName) });
			AssignmentCommander.FontColorOverride = AssignmentCommanderActive;
		}
	}

	public void SwitchState(LobbyGuiState state)
	{
		switch (state)
		{
		case LobbyGuiState.Default:
			CharacterSetupState.Visible = false;
			((Control)SplitContainer).Visible = true;
			break;
		case LobbyGuiState.CharacterSetup:
			CharacterSetupState.Visible = true;
			((Control)SplitContainer).Visible = false;
			((Control)this).UserInterfaceManager.GetUIController<LobbyUIController>().ReloadCharacterSetup();
			break;
		}
	}

	private void ChangeVisibility()
	{
		((BaseButton)ShowGUI).Pressed = !((BaseButton)ShowGUI).Pressed;
		((Control)BottomContainer).Visible = !((BaseButton)ShowGUI).Pressed;
	}

	private void OpenRankProgressWindow()
	{
		RankProgressWindow rankProgressWindow = new RankProgressWindow();
		((BaseWindow)rankProgressWindow).OpenCentered();
		rankProgressWindow.LoadRankData();
	}

